extern @abi(c-msvc-x64) fn ripple_change_new(arena_id: u64, kind: u32, target: u64,
                                              old_mhash: u64, new_mhash: u64) -> u64 from "ripple.iii"
extern @abi(c-msvc-x64) fn ripple_analyze(arena_id: u64, change_id: u64) -> u64 from "ripple.iii"
extern @abi(c-msvc-x64) fn ripple_execute(arena_id: u64, plan_id: u64, mode: u32) -> u64 from "ripple.iii"

var SITE_BUF  : [u8; 32]
var OLD_BUF   : [u8; 32]
var NEW_BUF   : [u8; 32]

fn fill32(p: u64, v: u8) -> u32 {
    let bp : *u8 = p as *u8
    let mut i : u64 = 0u64
    while i < 32u64 {
        bp[i] = v
        i = i + 1u64
    }
    return 0u32
}

fn main() -> u64 {
    witness_init()

    fill32(&SITE_BUF as u64, 0u8)
    fill32(&OLD_BUF as u64, 0xAAu8)
    fill32(&NEW_BUF as u64, 0xBBu8)

    /* arm 1: call ripple_analyze 9 times in the SAME arena.
     * Pre-fix: the 9th call would exhaust VEC64_LIVE (2 slots leaked per call,
     * 16 slots total -> full at 8th call -> 9th returns 0).
     * Post-fix: each call drops seeds+closure_v -> 0 net consumption -> 9th succeeds. */
