    if ar1 == 0u64 { return 1u64 }

    let tgt : u64 = crystal_mint(0u32, &SITE_BUF as u64, 0u64, 0u64)
    if tgt == 0u64 { return 2u64 }

    let mut call_n : u32 = 0u32
    let mut last_plan : u64 = 0u64
    while call_n < 9u32 {
        let chg : u64 = ripple_change_new(ar1, 1u32, tgt,
                                           &OLD_BUF as u64, &NEW_BUF as u64)
        if chg == 0u64 { return 10u64 }
        let plan : u64 = ripple_analyze(ar1, chg)
        if plan == 0u64 { return 11u64 }    /* FALSIFIER: pre-fix would fail here on call 9 */
