    let center : u64 = crystal_mint(0u32, &SITE_BUF as u64, 0u64, 0u64)
    if center == 0u64 { return 24u64 }
    crystal_edges_init(center, ar2)
    let e1 : u64 = crystal_mint(1u32, &SITE_BUF as u64, 0u64, 0u64)
    let e2 : u64 = crystal_mint(2u32, &SITE_BUF as u64, 0u64, 0u64)
    let e3 : u64 = crystal_mint(3u32, &SITE_BUF as u64, 0u64, 0u64)
    let e4 : u64 = crystal_mint(4u32, &SITE_BUF as u64, 0u64, 0u64)
    let e5 : u64 = crystal_mint(5u32, &SITE_BUF as u64, 0u64, 0u64)
    if e1 == 0u64 { return 25u64 }
    if e2 == 0u64 { return 26u64 }
    if e3 == 0u64 { return 27u64 }
    if e4 == 0u64 { return 28u64 }
    if e5 == 0u64 { return 29u64 }
    crystal_edges_add(center, e1)
    crystal_edges_add(center, e2)
    crystal_edges_add(center, e3)
    crystal_edges_add(center, e4)
    crystal_edges_add(center, e5)

    /* Manually build a plan crystal whose edge count = 5. */
    let chg5 : u64 = ripple_change_new(ar2, 1u32, center,
                                        &OLD_BUF as u64, &NEW_BUF as u64)
    if chg5 == 0u64 { return 30u64 }
